class MinRange:
    def __init__(self, n, default):
        self.N = 1
        while self.N < n:
            self.N *= 2
        self.default = default
        self.seg = [default] * (2 * self.N)
    def set(self, i, v):
        i += self.N
        self.seg[i] = v
        i //= 2
        while i:
            self.seg[i] = min(self.seg[2*i], self.seg[2*i+1])
            i //= 2
    def range_min(self, l, r):
        l += self.N; r += self.N
        resL = self.default; resR = self.default
        while l <= r:
            if (l % 2) == 1:
                resL = min(resL, self.seg[l]); l += 1
            if (r % 2) == 0:
                resR = min(self.seg[r], resR); r -= 1
            l //= 2; r //= 2
        return min(resL, resR)

