    def __init__(self, n, default):
        self.N = 1
        while self.N < n:
            self.N *= 2
        self.default = default
        self.seg = [default] * (2 * self.N)
    def set(self, i, v):
        i += self.N
        self.seg[i] = v
    def range_min(self, l, r):
        l += self.N; r += self.N
        ans = self.default
        while l < r:
            if l & 1:
                ans = min(ans, self.seg[l]); l += 1
            if not (r & 1):
                ans = min(ans, self.seg[r]); r -= 1
            l >>= 1; r >>= 1
        return ans

